// MAESTRO BD - JOIN COMPLETO
// Llaves: NIC=CUENTA(balanza) | NIC=PRODUCTO(ctrl_op) | NIC=NIC(obs)

const inp = $input.first().json;
const asigRows = inp.asignacion_rows    || [];
const balRows  = inp.balanza_rows       || [];
const ctrlRows = inp.control_op_rows   || [];
const obsRows  = inp.observaciones_rows || [];

// Indice Balanza por CUENTA
const balMap = {};
for (const r of balRows) {
  const k = r['CUENTA'];
  if (k != null && k !== '') balMap[String(k)] = r;
}

// Indice Control OP por PRODUCTO
const ctrlMap = {};
for (const r of ctrlRows) {
  const k = r['PRODUCTO'];
  if (k != null && k !== '') ctrlMap[String(k)] = r;
}

// Indice Observaciones por NIC
const obsMap = {};
for (const r of obsRows) {
  const nic = r['NIC'];
  if (nic == null || nic === '') continue;
  const partes = [
    (r['OBS_SS']             || '').toString().trim(),
    (r['OBS_RI']             || '').toString().trim(),
    (r['OBS_PAS_COMENTARIO'] || '').toString().trim()
  ].filter(p => p !== '');
  if (partes.length > 0) obsMap[String(nic)] = partes.join(' | ');
}

// Helper: serial Excel -> DD/MM/YYYY
function serialToDate(v) {
  if (!v) return '';
  if (v instanceof Date) {
    const d = String(v.getUTCDate()).padStart(2,'0');
    const m = String(v.getUTCMonth()+1).padStart(2,'0');
    return `${d}/${m}/${v.getUTCFullYear()}`;
  }
  if (typeof v === 'number') {
    const dt = new Date(Math.round((v - 25569) * 86400000));
    const d = String(dt.getUTCDate()).padStart(2,'0');
    const m = String(dt.getUTCMonth()+1).padStart(2,'0');
    return `${d}/${m}/${dt.getUTCFullYear()}`;
  }
  return String(v);
}

// Construir Maestro BD
const result = [];
for (const a of asigRows) {
  const nic = a['NIC'];
  const ns  = nic != null ? String(nic) : '';

  const row = {
    // GRUPO 1 - Asignacion (cols 1-28)
    Num_Lote:               a['Num_Lote']             || '',
    Tecnico:                a['Tecnico'] || a['Técnico'] || '',
    Orden:                  a['Orden']                || '',
    Tip_Orden:              a['Tip_Orden']            || '',
    NIC:                    nic                       || '',
    Zona:                   a['Zona']                 || '',
    Departamento:           a['Departamento']         || '',
    Municipio:              a['Municipio']            || '',
    Corregimiento:          a['Corregimiento']        || '',
    Localidad:              a['Localidad']            || '',
    Tip_Via:                a['Tip_Via']              || '',
    Nom_Calle:              a['Nom_Calle']            || '',
    Duplicador:             a['Duplicador']           || '',
    Num_Puerta:             a['Num_Puerta']           || '',
    Direccion:              a['Direccion']            || '',
    Dir_Referencia:         a['Dir_Referencia']       || '',
    Nombre_Cliente:         a['Nombre Cliente']       || '',
    Tarifa:                 a['Tarifa']               || '',
    Deuda_Vencida:          a['Deuda Vencida']        || '',
    Facturas_Vencidas_Asig: a['Facturas Vencidas']    || '',
    N_Medidor:              a['N° Medidor']           || '',
    Marca_Medidor_Asig:     a['Marca Medidor']        || '',
    Antiguedad:             a['Antiguedad']           || '',
    Estado:                 a['Estado']               || '',
    CT_Gestor:              a['CT Gestor']            || '',
    Comentario:             a['Comentario']           || '',
    Tipo_Suspension_SCR:    a['Tipo_Suspension(SCR)'] || '',
    Estado_del_Servicio:    a['Estado del Servicio']  || '',

    // GRUPO 2 - Balanza (cols 29-31)
    Deuda_Hoy:              '',
    Fecha_de_Vencimiento:   '',
    Facturas_Vencidas:      '',

    // GRUPO 3 - Control OP (cols 32-40)
    Nombre_del_Cliente:     '',
    Tarifa_CtrlOp:          '',
    Marca_Medidor:          '',
    Numero_de_medidor:      '',
    Municipio_CtrlOp:       '',
    Corregimiento_CtrlOp:   '',
    Barrio:                 '',
    Direccion_CtrlOp:       '',
    Multifamiliar:          '',

    // Pendientes - futuras automatizaciones
    Material_en_Bodega:     '',
    Maestro_Zona:           '',
    Priorizacion:           '',
    Exclusiones_Temporal:   '',
    Exclusiones_por_Campo:  '',
    Tipo_Brigada:           '',
    Cluster:                '',

    // Observacion concatenada
    Observacion:            ''
  };

  // Cruce Balanza (NIC = CUENTA)
  if (ns && balMap[ns]) {
    const b = balMap[ns];
    row.Deuda_Hoy           = b['Suma de Deuda_Energia (BDEF)'] ?? '';
    row.Fecha_de_Vencimiento = serialToDate(b['Fecha_vencimiento']);
    row.Facturas_Vencidas   = b['Suma de Facturas'] ?? '';
  }

  // Cruce Control OP (NIC = PRODUCTO)
  if (ns && ctrlMap[ns]) {
    const c = ctrlMap[ns];
    row.Nombre_del_Cliente   = c['NOMBRE_CLIENTE']       || '';
    row.Tarifa_CtrlOp        = c['TARIFA']               || '';
    row.Marca_Medidor        = c['MARCA_MEDIDOR']        || '';
    row.Numero_de_medidor    = c['ID_MEDIDOR']           || '';
    row.Municipio_CtrlOp     = c['MUNICIPIO']            || '';
    row.Corregimiento_CtrlOp = c['CORREGIMIENTO']        || '';
    row.Barrio               = c['BARRIO']               || '';
    row.Direccion_CtrlOp     = c['DIRECCION_CLIENTE']    || '';
    row.Multifamiliar        = c['NOMBRE MULTIFAMILIAR'] || '';
  }

  // Cruce Observaciones (NIC = NIC)
  if (ns && obsMap[ns]) row.Observacion = obsMap[ns];

  result.push({ json: row });
}

return result;
